Javascript.logic:
var opt = Services.getValue(NewAddressForService.dataBinding);

Services.setValue( NewPostcode.dataBinding, "");

if( 'ACK' == opt && null != solNode )
{	var pcNode = solNode.selectSingleNode("./ContactDetails/Address/PostCode");
	if( 'ACK' == opt && null != pcNode)
	{ Services.setValue(NewPostcode.dataBinding, XML.getNodeTextContent( pcNode ));}
}
else if( 'ADDR' == opt && null != defNode )
{	Services.setValue(NewPostcode.dataBinding, XML.getNodeTextContent( defNode.selectSingleNode("./ContactDetails/Address/PostCode")));
}
